  for($c=0;$c -lt $nc;$c++){ $ws.Cells.Item(2,$c+1).Value2 = $cols[$c] }
  $hdr = $ws.Range($ws.Cells.Item(2,1), $ws.Cells.Item(2,$nc))
  $hdr.Font.Bold = $true; $hdr.Interior.Color = 15983833; $hdr.HorizontalAlignment = -4108; $hdr.VerticalAlignment = -4108; $hdr.WrapText = $true

  $sum = @(0,0,0,0,0,0)
  foreach($d in $rows){ if(([string]$d[0]) -ne "__HDR__"){ for($j=0;$j -lt 6;$j++){ $vv=$d[$j+3]; if("$vv" -match '^\d+(\.\d+)?$'){ $sum[$j]+=[double]$vv } } } }

  $startRow = 3; $ndr = $rows.Count; $hdrRowsX = @(); $rw = $startRow
  for($i=0;$i -lt $ndr;$i++){
    $d = $rows[$i]; $tag = [string]$d[0]
    if($tag -eq "__HDR__"){ $ws.Cells.Item($rw,1).Value2 = [string]$d[1]; $hdrRowsX += $rw }
    else { for($c=0;$c -lt $nc;$c++){ $v="$($d[$c])"; if($v.Trim().Length -gt 0){ $ws.Cells.Item($rw,$c+1).Value2 = $v } } }
    $rw++
  }
  $totalRowX = $rw
  $ws.Cells.Item($rw,3).Value2 = "ВСЕГО"
  for($j=0;$j -lt 6;$j++){ $ws.Cells.Item($rw,$j+4).Value2 = "$([int]$sum[$j])" }
