  for($col=4;$col -le 9;$col++){ $rngN = $ws.Range($ws.Cells.Item($startRow,$col), $ws.Cells.Item($last,$col)); [void]$rngN.TextToColumns($ws.Cells.Item($startRow,$col), 1) }
