  for($b=7;$b -le 12;$b++){ $all.Borders.Item($b).LineStyle = 1; $all.Borders.Item($b).Weight = 2 }
  $all.VerticalAlignment = -4160
  $ws.Columns.Item(3).WrapText = $true; $ws.Columns.Item(10).WrapText = $true; $ws.Columns.Item(11).WrapText = $true; $ws.Columns.Item(12).WrapText = $true
